if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first().json.body;
const now = new Date().toISOString().split('T')[0] + ' ' + new Date().toISOString().split('T')[1].substring(0,8) + ' UTC';
const session = body.session || 'UNKNOWN';

// Normalize any field into a markdown-ready string.
// Accepts: string, array of strings/objects, object, null, undefined, empty.
// Returns: 'N/A' (for completed/next_steps) or 'None' (for broken_blocked) by default,
// or a properly bulleted list if an array, or stringified object, or the raw string.
function normalize(raw, emptyDefault) {
  if (raw === undefined || raw === null || raw === '') return emptyDefault;
  if (Array.isArray(raw)) {
    if (raw.length === 0) return emptyDefault;
    return raw.map(i => typeof i === 'string' ? '- ' + i : '- ' + JSON.stringify(i)).join('\n');
  }
  if (typeof raw === 'object') return JSON.stringify(raw, null, 2);
  return String(raw);
}

const completed = normalize(body.completed, 'N/A');
// broken_blocked is the preferred field name; broken is the legacy field name.
const brokenRaw = body.broken_blocked !== undefined ? body.broken_blocked : body.broken;
const broken = normalize(brokenRaw, 'None');
const next_steps = normalize(body.next_steps, 'N/A');

const head_commit = body.head_commit || 'N/A';
const line_count = body.line_count || 'N/A';
const deploy_count = body.deploy_count || 'N/A';
const summary = body.summary || '';
const markdown = `# GDA Command \u2014 Master Status\n\n**Last Updated:** ${now}\n**Session:** ${session}\n**HEAD Commit:** \`${head_commit}\`\n**Line Count:** ${line_count}\n**Deploy Count:** ${deploy_count}\n\n---\n\n## Summary\n${summary}\n\n## Completed\n${completed}\n\n## Broken / Blocked\n${broken}\n\n## Next Steps\n${next_steps}\n\n---\n*Auto-updated via gda-gist-update webhook*\n`;
return [{ json: { content: markdown } }];
